'use client'

import { useEffect, useState } from 'react'

const SPINNER_SRC = 'data:image/png;base64,'
const HERO_SRC = 'data:image/jpeg;base64,'

export default function LoadingScreen() {
  const [showBg, setShowBg]           = useState(false)
  const [showText, setShowText]       = useState(false)
  const [showSub, setShowSub]         = useState(false)
  const [showArena, setShowArena]     = useState(false)
  const [arenaRun, setArenaRun]       = useState(false)
  const [fadeOut, setFadeOut]         = useState(false)
  const [done, setDone]               = useState(false)

  useEffect(() => {
    let animFrame: number
    const startTime = performance.now()
    // Constant speed for 2s then decelerate for 2s
    // V0=0.24 deg/ms (≈4 deg/frame), total angle = 0.24*2000 + 0.24*2000*0.5 = 480+240 = 720° = 2 rotations → right-side up
    const CONST_MS = 2000
    const DECEL_MS = 2000
    const V0 = 0.24

    let bgDone = false, textDone = false, subDone = false

    function tick(now: number) {
      const elapsed = now - startTime

      if (!bgDone   && elapsed >= 800)  { bgDone   = true; setShowBg(true) }
      if (!textDone && elapsed >= 1500) { textDone = true; setShowText(true) }
      if (!subDone  && elapsed >= 2200) { subDone  = true; setShowSub(true) }

      const spinner = document.getElementById('fl-spinner') as HTMLElement | null
      const totalSpin = CONST_MS + DECEL_MS

      if (elapsed < CONST_MS) {
        const angle = V0 * elapsed
        if (spinner) spinner.style.transform = `translate(-50%, -50%) rotate(${angle}deg)`
        animFrame = requestAnimationFrame(tick)
      } else if (elapsed < totalSpin) {
        const t = elapsed - CONST_MS
        const p = t / DECEL_MS
        const angle = V0 * CONST_MS + V0 * DECEL_MS * (p - p * p / 2)
        if (spinner) spinner.style.transform = `translate(-50%, -50%) rotate(${angle}deg)`
        animFrame = requestAnimationFrame(tick)
      } else {
        if (spinner) spinner.style.transform = 'translate(-50%, -50%) rotate(0deg)'
        setTimeout(() => setShowArena(true), 200)
        setTimeout(() => setArenaRun(true),  350)
        setTimeout(() => setFadeOut(true),   5800)
        setTimeout(() => {
          setDone(true)
          window.dispatchEvent(new Event('loadingDone'))
        }, 6600)
      }
    }

    animFrame = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(animFrame)
  }, [])

  if (done) return null

  return (
    <div style={{
      position: 'fixed', inset: 0, background: '#000',
      zIndex: 9999,
      opacity: fadeOut ? 0 : 1,
      transition: 'opacity 0.8s ease',
      pointerEvents: fadeOut ? 'none' : 'auto',
    }}>
      {/* Hero background */}
      <div style={{ position: 'absolute', inset: 0, overflow: 'hidden' }}>
        <img
          src={HERO_SRC}
          style={{
            width: '100%', height: '100%',
            objectFit: 'cover', objectPosition: 'center 30%',
            opacity: showBg ? 1 : 0,
            filter: 'grayscale(100%) brightness(0.55)',
            transition: 'opacity 1.8s ease',
          }}
          alt=""
        />
      </div>
      <div style={{
        position: 'absolute', inset: 0,
        background: 'radial-gradient(ellipse at center, transparent 10%, rgba(0,0,0,0.82) 100%)',
      }} />

      {/* Bot icon — spins in place at screen center */}
      <img
        id="fl-spinner"
        src="/bot-king.png"
        alt=""
        style={{
          position: 'absolute',
          top: '50%', left: '50%',
          transform: 'translate(-50%, -50%)',
          width: 120, height: 120, objectFit: 'contain',
          zIndex: 11,
        }}
      />

      {/* Florent / Code League — fades in above bot */}
      <div style={{
        position: 'absolute',
        bottom: '50%', left: '50%',
        transform: 'translateX(-50%) translateY(-80px)',
        textAlign: 'center', whiteSpace: 'nowrap',
        opacity: showText ? 1 : 0,
        transition: 'opacity 1.2s ease',
        zIndex: 11,
      }}>
        <div style={{ lineHeight: 1, display: 'flex', flexDirection: 'column', gap: 10 }}>
          <span style={{
            display: 'block',
            fontFamily: "'HKGrotesk', 'Helvetica Neue', Arial, sans-serif",
            fontSize: 80, fontWeight: 700,
            letterSpacing: '0.04em', color: '#fff',
            textTransform: 'uppercase',
          }}>FLORENT</span>
          <span style={{
            display: 'block',
            fontFamily: "'Courier New', Courier, monospace",
            fontSize: 28, fontWeight: 400,
            letterSpacing: '0.12em',
            color: '#FF5500',
          }}>&lt;CODE LEAGUE&gt;</span>
        </div>
      </div>

      {/* Nordic Programming Championship — fades in below bot */}
      <div style={{
        position: 'absolute',
        top: '50%', left: '50%',
        transform: 'translateX(-50%) translateY(90px)',
        textAlign: 'center', whiteSpace: 'normal',
        width: '80vw', maxWidth: 400,
        opacity: showSub ? 1 : 0,
        transition: 'opacity 1.2s ease',
        zIndex: 11,
      }}>
        <div style={{ width: 1, height: 32, background: 'rgba(255,255,255,0.2)', margin: '0 auto 20px' }} />
        <div style={{
          fontFamily: "'HKGrotesk', 'Neue Haas Grotesk', 'Helvetica Neue', Arial, sans-serif",
          fontSize: 'clamp(11px, 3vw, 15px)', letterSpacing: '0.22em',
          color: 'rgba(255,255,255,0.9)',
        }}>Nordic Programming Championship</div>
      </div>

      {/* Entering the arena */}
      <div style={{
        position: 'absolute', bottom: 80,
        left: '50%', transform: 'translateX(-50%)',
        zIndex: 10, display: 'flex', flexDirection: 'column',
        alignItems: 'center', gap: 16,
        opacity: showArena ? 1 : 0,
        transition: 'opacity 0.8s ease',
      }}>
        <div style={{
          fontFamily: 'Courier New, monospace',
          fontSize: 13, letterSpacing: '0.25em',
          textTransform: 'uppercase', color: 'rgba(255,255,255,0.7)',
        }}>Entering the arena</div>
        <div style={{
          width: 280, height: 2,
          background: 'rgba(255,255,255,0.15)',
          position: 'relative', overflow: 'hidden',
        }}>
          <div style={{
            position: 'absolute', left: arenaRun ? 0 : '-100%', top: 0, bottom: 0, width: '100%',
            background: '#FF5500',
            transition: 'left 3.2s ease 0.1s',
          }} />
        </div>
      </div>
    </div>
  )
}
